cd ~/Projects/nonprofit-data-classification && python3 -c "
import json
for f in ['src/data/nonprofit-data-taxonomy.json', 'src/data/handling-matrix.json', 'src/data/workspace-features.json']:
    with open(f) as fh:
        data = json.load(fh)
    if 'categories' in data:
        total = sum(len(c['dataTypes']) for c in data['categories'])
        print(f'{f}: {len(data[\"categories\"])} categories, {total} data types')
    elif 'controls' in data:
        print(f'{f}: {len(data[\"controls\"])} controls')
    elif 'tiers' in data:
        print(f'{f}: {len(data[\"tiers\"])} workspace tiers')
"

