/* ─── Shared helpers ─────────────────────────────────────────────────── */

const FONT = 'Calibri'
const BODY_SIZE = 22 // half-points (11pt)
const H1_SIZE = 28   // 14pt
const H2_SIZE = 24   // 12pt

function body(text, opts = {}) {
  return new TextRun({ text, font: FONT, size: BODY_SIZE, ...opts })
}

function bodyParagraph(text, opts = {}) {
  return new Paragraph({
    spacing: { after: 120 },
    ...opts,
    children: [body(text)],
  })
}

function heading1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 240, after: 120 },
    children: [
      new TextRun({
        text,
        font: FONT,
        size: H1_SIZE,
        bold: true,
        color: COLORS.emerald,
      }),
    ],
  })
}

function heading2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 200, after: 80 },
    children: [
      new TextRun({
        text,
        font: FONT,
        size: H2_SIZE,
        bold: true,
        color: COLORS.stone,
      }),
    ],
  })
}

function bulletItem(text) {
  return new Paragraph({
    bullet: { level: 0 },
    spacing: { after: 60 },
    children: [body(text)],
  })
}

function numberedItem(text) {
  return new Paragraph({
    numbering: { reference: 'numbered-list', level: 0 },
    spacing: { after: 60 },
    children: [body(text)],
  })
}

function pageBreak() {
  return new Paragraph({ children: [new PageBreak()] })
}

function emptyParagraph() {
  return new Paragraph({ spacing: { after: 60 }, children: [] })
}

/* ─── Table helpers ──────────────────────────────────────────────────── */

const TABLE_BORDERS = {
  top: { style: BorderStyle.SINGLE, size: 1, color: 'cccccc' },
  bottom: { style: BorderStyle.SINGLE, size: 1, color: 'cccccc' },
  left: { style: BorderStyle.SINGLE, size: 1, color: 'cccccc' },
  right: { style: BorderStyle.SINGLE, size: 1, color: 'cccccc' },
}

function headerCell(text, shading = COLORS.emerald, width) {
  return new TableCell({
    width: width ? { size: width, type: WidthType.PERCENTAGE } : undefined,
    shading: { type: ShadingType.SOLID, color: shading },
    borders: TABLE_BORDERS,
    children: [
      new Paragraph({
        spacing: { before: 40, after: 40 },
        children: [
          new TextRun({
            text,
            font: FONT,
            size: 20,
            bold: true,
            color: COLORS.white,
          }),
        ],
      }),
    ],
  })
}

function textCell(text, shading, width) {
  return new TableCell({
    width: width ? { size: width, type: WidthType.PERCENTAGE } : undefined,
    shading: shading
      ? { type: ShadingType.SOLID, color: shading }
      : undefined,
    borders: TABLE_BORDERS,
    children: [
      new Paragraph({
        spacing: { before: 40, after: 40 },
        children: [body(text)],
      }),
    ],
  })
}

/* ─── Section builders ───────────────────────────────────────────────── */

